mapper.select:
select id, event_id, request_id, room_id, user_id, nickname, amount, bid_version, bid_time
from auction_bid_record
where event_id = #{eventId}

select id, event_id, request_id, room_id, user_id, nickname, amount, bid_version, bid_time
from auction_bid_record
where request_id = #{requestId}

select id, event_id, request_id, room_id, user_id, nickname, amount, bid_version, bid_time
from auction_bid_record
where room_id = #{roomId}
order by bid_version desc, id desc
limit #{limit}

select count(*)
from auction_bid_record
where room_id = #{roomId}
